UPDATE CUSTOMER_SUPPORT
   SET CS_TITLE = #{csTitle}
     , CS_CONTENT = #{csContent}
     , CS_PIN_YN = IFNULL(#{csPinYn}, 'N')
     , CS_UP_DATE = NOW()
 WHERE CS_NO = #{csNo}
   AND CS_CAT_CD = 'CSS001'
   AND CS_USE_YN = 'Y'


